    public Object createOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = this.market(symbol);
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            throw new ArgumentsRequired((String)Helpers.add(this.id, " createOrder() requires a side argument")) ;
        }
        Object id = Helpers.GetValue(market, "id");
        final Object finalSide = side;
        Object request = new java.util.HashMap<String, Object>() {{
            put( "symbol", id );
            put( "side", ((String)finalSide).toUpperCase() );
        }};
        if (Helpers.isTrue(!Helpers.isEqual(price, null)))
        {
            Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
        }
        Object cost = null;
        var costparametersVariable = this.handleParamString(parameters, "cost");
        cost = ((java.util.List<Object>) costparametersVariable).get(0);
        parameters = ((java.util.List<Object>) costparametersVariable).get(1);
        if (Helpers.isTrue(Helpers.isEqual(type, "market")))
        {
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(cost, null)) && Helpers.isTrue(Helpers.isEqual(side, "buy"))))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " createOrder() requires params[\"cost\"] for market buy order")) ;
            } else
            {
                Helpers.addElementToObject(request, "quantity", this.costToPrecision(symbol, cost));
            }
        } else
        {
            Helpers.addElementToObject(request, "quantity", this.amountToPrecision(symbol, amount));
        }
        Object isPostOnly = null;
        var isPostOnlyparametersVariable = this.handlePostOnly(Helpers.isEqual(type, "market"), false, parameters);
        isPostOnly = ((java.util.List<Object>) isPostOnlyparametersVariable).get(0);
        parameters = ((java.util.List<Object>) isPostOnlyparametersVariable).get(1);
        if (Helpers.isTrue(isPostOnly))
        {
            Helpers.addElementToObject(request, "type", "LIMIT_MAKER");
        } else
        {
            Helpers.addElementToObject(request, "type", ((String)type).toUpperCase());
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(request, parameters));
    }

    public Object createContractOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = this.market(symbol);
        Object request = new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.GetValue(market, "id") );
            put( "quantity", ToobitCore.this.amountToPrecision(symbol, amount) );
        }};
        Object reduceOnly = null;
        var reduceOnlyparametersVariable = this.handleParamBool(parameters, "reduceOnly");
        reduceOnly = ((java.util.List<Object>) reduceOnlyparametersVariable).get(0);
        parameters = ((java.util.List<Object>) reduceOnlyparametersVariable).get(1);
        if (Helpers.isTrue(Helpers.isEqual(side, "buy")))
        {
            side = ((Helpers.isTrue(reduceOnly))) ? "SELL_CLOSE" : "BUY_OPEN";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "sell")))
        {
            side = ((Helpers.isTrue(reduceOnly))) ? "BUY_CLOSE" : "SELL_OPEN";
        }
        Helpers.addElementToObject(request, "side", side);
        if (Helpers.isTrue(!Helpers.isEqual(price, null)))
        {
            Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
        }
        if (Helpers.isTrue(this.inArray(type, new java.util.ArrayList<Object>(java.util.Arrays.asList("limit", "LIMIT")))))
        {
            Helpers.addElementToObject(request, "type", ((String)type).toUpperCase());
            Helpers.addElementToObject(request, "price", this.priceToPrecision(symbol, price));
        } else if (Helpers.isTrue(Helpers.isEqual(type, "market")))
        {
            Helpers.addElementToObject(request, "type", "LIMIT"); // weird, but exchange works this way
            Helpers.addElementToObject(request, "priceType", "MARKET");
        }
        Object isPostOnly = null;
        var isPostOnlyparametersVariable = this.handlePostOnly(Helpers.isEqual(type, "market"), false, parameters);
        isPostOnly = ((java.util.List<Object>) isPostOnlyparametersVariable).get(0);
        parameters = ((java.util.List<Object>) isPostOnlyparametersVariable).get(1);
        if (Helpers.isTrue(isPostOnly))
        {
            Helpers.addElementToObject(request, "timeInForce", "LIMIT_MAKER");
        }
        Object values = this.handleTriggerPricesAndParams(symbol, parameters);
        Object triggerPrice = Helpers.GetValue(values, 0);
        parameters = Helpers.GetValue(values, 3);
        if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
        {
            Helpers.addElementToObject(request, "stopPrice", triggerPrice);
        }
        Object stopLoss = this.safeDict(parameters, "stopLoss");
        Object takeProfit = this.safeDict(parameters, "takeProfit");
        Object hasStopLoss = (!Helpers.isEqual(stopLoss, null));
        Object hasTakeProfit = (!Helpers.isEqual(takeProfit, null));
        Object triggerPriceTypes = new java.util.HashMap<String, Object>() {{
            put( "mark", "MARK_PRICE" );
            put( "last", "CONTRACT_PRICE" );
        }};
        if (Helpers.isTrue(hasStopLoss))
        {
            Helpers.addElementToObject(request, "stopLoss", this.safeValue(stopLoss, "triggerPrice"));
            Object limitPrice = this.safeValue(stopLoss, "price");
            if (Helpers.isTrue(!Helpers.isEqual(limitPrice, null)))
            {
                Helpers.addElementToObject(request, "slOrderType", "LIMIT");
                Helpers.addElementToObject(request, "slLimitPrice", this.priceToPrecision(symbol, limitPrice));
            }
            Object triggerPriceType = this.safeString(stopLoss, "triggerPriceType");
            if (Helpers.isTrue(!Helpers.isEqual(triggerPriceType, null)))
            {
                Helpers.addElementToObject(request, "slTriggerBy", this.safeString(triggerPriceTypes, triggerPriceType, triggerPriceType));
            }
            parameters = this.omit(parameters, "stopLoss");
        }
        if (Helpers.isTrue(hasTakeProfit))
        {
            Helpers.addElementToObject(request, "takeProfit", this.safeValue(takeProfit, "triggerPrice"));
            Object limitPrice = this.safeValue(takeProfit, "price");
            if (Helpers.isTrue(!Helpers.isEqual(limitPrice, null)))
            {
                Helpers.addElementToObject(request, "tpOrderType", "LIMIT");
                Helpers.addElementToObject(request, "tpLimitPrice", this.priceToPrecision(symbol, limitPrice));
            }
            Object triggerPriceType = this.safeString(takeProfit, "triggerPriceType");
            if (Helpers.isTrue(!Helpers.isEqual(triggerPriceType, null)))
            {
                Helpers.addElementToObject(request, "tpTriggerBy", this.safeString(triggerPriceTypes, triggerPriceType, triggerPriceType));
            }
            parameters = this.omit(parameters, "takeProfit");
        }
        if (!Helpers.isTrue((Helpers.inOp(parameters, "newClientOrderId"))))
        {
            Helpers.addElementToObject(request, "newClientOrderId", this.uuid());
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(request, parameters));
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder, cancelOrder
        //
        //     {
        //         "symbol": "ETHUSDT",
        //         "price": "0",
        //         "origQty": "0.001",
        //         "orderId": "2024837825254460160",
        //         "clientOrderId": "1756115478113679",
        //         "executedQty": "0",
        //         "status": "PENDING_NEW",
        //         "timeInForce": "GTC",
        //         "type": "MARKET",
        //         "side": "SELL"
        //         "accountId": "1783404067076253952",    // only in spot
        //         "symbolName": "ETHUSDT",               // only in spot
        //         "transactTime": "1756115478604",       // only in spot
        //         "time": "1668418485058",               // only in contract
        //         "updateTime": "1668418485058",         // only in contract
        //         "leverage": "2",                       // only in contract
        //         "avgPrice": "0",                       // only in contract
        //         "marginLocked": "9.5",                 // only in contract
        //         "priceType": "INPUT"                   // only in contract
        //     }
        //
        //
        // fetchOrder, fetchOrders, fetchOpenOrders
        //
        //    {
        //        "time": "1756140208069",
        //        "updateTime": "1756140208078",
        //        "orderId": "2025045271033977089",
        //        "clientOrderId": "17561402075722006",
        //        "symbol": "ETHUSDT",
        //        "price": "3000",
        //        "origQty": "0.002",
        //        "executedQty": "0",
        //        "avgPrice": "0",
        //        "type": "LIMIT",
        //        "side": "BUY",
        //        "timeInForce": "GTC",
        //        "status": "NEW",
        //        "accountId": "1783404067076253952",  // only in SPOT
        //        "exchangeId": "301",                 // only in SPOT
        //        "symbolName": "ETHUSDT",             // only in SPOT
        //        "cummulativeQuoteQty": "0",          // only in SPOT
        //        "cumulativeQuoteQty": "0",           // only in SPOT
        //        "stopPrice": "0.0",                  // only in SPOT
        //        "icebergQty": "0.0",                 // only in SPOT
        //        "isWorking": true                    // only in SPOT
        //        "leverage": "2",                     // only in CONTRACT
        //        "marginLocked": "9.5",               // only in CONTRACT
        //        "priceType": "INPUT"                 // only in CONTRACT
        //        "triggerType": "0",                  // only in CONTRACT fetchClosedOrders
        //        "fallType": "0",                     // only in CONTRACT fetchClosedOrders
        //        "activeStatus": "0"                  // only in CONTRACT fetchClosedOrders
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger2(order, "transactTime", "time");
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object rawType = this.safeString(order, "type");
        Object rawSideLower = this.safeStringLower(order, "side");
        Object triggerPrice = this.omitZero(this.safeString(order, "stopPrice"));
        if (Helpers.isTrue(Helpers.isEqual(triggerPrice, "0.0")))
        {
            triggerPrice = null;
        }
        final Object finalMarket = market;
        final Object finalRawType = rawType;
        final Object finalTriggerPrice = triggerPrice;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", ToobitCore.this.safeString(order, "orderId") );
            put( "clientOrderId", ToobitCore.this.safeString(order, "clientOrderId") );
            put( "timestamp", timestamp );
            put( "datetime", ToobitCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "lastUpdateTimestamp", ToobitCore.this.safeInteger(order, "updateTime") );
            put( "status", ToobitCore.this.parseOrderStatus(ToobitCore.this.safeString(order, "status")) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", ToobitCore.this.parseOrderType(finalRawType) );
            put( "timeInForce", ToobitCore.this.safeString(order, "timeInForce") );
            put( "postOnly", (Helpers.isEqual(finalRawType, "LIMIT_MAKER")) );
            put( "side", rawSideLower );
            put( "price", ToobitCore.this.omitZero(ToobitCore.this.safeString(order, "price")) );
            put( "triggerPrice", finalTriggerPrice );
            put( "cost", ToobitCore.this.omitZero(ToobitCore.this.safeString(order, "cumulativeQuoteQty")) );
            put( "average", ToobitCore.this.safeString(order, "avgPrice") );
            put( "amount", ToobitCore.this.safeString(order, "origQty") );
            put( "filled", ToobitCore.this.safeString(order, "executedQty") );
            put( "remaining", null );
            put( "trades", null );
            put( "fee", null );
            put( "marginMode", null );
            put( "reduceOnly", null );
            put( "leverage", null );
            put( "hedged", null );
        }}, market);
    }

    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "PENDING_NEW", "open" );
            put( "NEW", "open" );
            put( "PARTIALLY_FILLED", "open" );
            put( "FILLED", "closed" );
            put( "PENDING_CANCEL", "canceled" );
            put( "CANCELED", "canceled" );
            put( "REJECTED", "canceled" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        return this.safeString(statuses, status, status);
    }

    public Object parseOrderType(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "MARKET", "market" );
            put( "LIMIT", "limit" );
            put( "LIMIT_MAKER", "limit" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name toobit#cancelOrder
     * @description cancels an open order
     * @see https://toobit-docs.github.io/apidocs/spot/v1/en/#cancel-order-trade
     * @see https://toobit-docs.github.io/apidocs/usdt_swap/v1/en/#cancel-order-trade
     * @param {string} id order id
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(Helpers.isEqual(this.safeString(parameters, "clientOrderId"), null)))
            {
                Helpers.addElementToObject(request, "orderId", id);
            }
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("cancelOrder", market, parameters, "none");
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(marketType, "none")))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a symbol argument or the \"defaultType\" parameter to be set to \"spot\" or \"swap\"")) ;
            }
            Object response = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(Helpers.isEqual(marketType, "spot")))
            {
                response = (this.privateDeleteApiV1SpotOrder(this.extend(request, parameters))).join();
            } else
            {
                response = (this.privateDeleteApiV1FuturesOrder(this.extend(request, parameters))).join();
            }
            // response same as in `createOrder`
            Object status = this.parseOrderStatus(this.safeString(response, "status"));
            if (Helpers.isTrue(!Helpers.isEqual(status, "open")))
            {
                throw new OrderNotFound((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " order "), id), " can not be canceled, "), this.json(response))) ;
            }
            return this.parseOrder(response, market);
        });

    }

