    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(item, "coinId");
        currency = this.safeCurrency(currencyId, currency);
        Object timestamp = this.safeInteger(item, "created");
        Object after = this.safeNumber(item, "total");
        Object amountRaw = this.safeString(item, "change", "");
        Object amount = this.parseNumber(Precise.stringAbs(amountRaw));
        Object direction = "in";
        if (Helpers.isTrue(((String)amountRaw).startsWith(((String)"-"))))
        {
            direction = "out";
        }
        final Object finalDirection = direction;
        final Object finalCurrency = currency;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", ToobitCore.this.safeString(item, "id") );
            put( "timestamp", timestamp );
            put( "datetime", ToobitCore.this.iso8601(timestamp) );
            put( "direction", finalDirection );
            put( "account", null );
            put( "referenceId", null );
            put( "referenceAccount", null );
            put( "type", ToobitCore.this.parseLedgerType(ToobitCore.this.safeString(item, "flowType")) );
            put( "currency", Helpers.GetValue(finalCurrency, "code") );
            put( "amount", amount );
            put( "before", null );
            put( "after", after );
            put( "status", null );
            put( "fee", null );
        }}, currency);
    }

    public Object parseLedgerType(Object type)
    {
        Object types = new java.util.HashMap<String, Object>() {{
            put( "USER_ACCOUNT_TRANSFER", "transfer" );
            put( "AIRDROP", "rebate" );
        }};
        return this.safeString(types, type, type);
    }

