    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits & fetchWithdrawals
        //
        //     {
        //         "time": 1499865549590,
        //         "id": 100234,
        //         "coinName": "EOS",
        //         "statusCode": "DEPOSIT_CAN_WITHDRAW",
        //         "status": "2", // 2=SUCCESS, 11=REJECT, 12=AUDIT
        //         "address": "deposit2bb",
        //         "txId": "98A3EA560C6B3336D348B6C83F0F95ECE4F1F5919E94BD006E5BF3BF264FACFC",
        //         "txIdUrl": "",
        //         "requiredConfirmTimes": "5",
        //         "confirmTimes": "5",
        //         "quantity": "1.01",
        //         "coin": "EOS",                     // present in "fetchDeposits"
        //         "coinId ":"BHC",                   // present in "fetchWithdrawals"
        //         "addressTag": "19012584",          // present in "fetchDeposits"
        //         "addressExt":"address tag",        // present in "fetchWithdrawals"
        //         "fromAddress": "clarkkent",        // present in "fetchDeposits"
        //         "fromAddressTag": "19029901"       // present in "fetchDeposits"
        //         "arriveQuantity":"14",             // present in "fetchWithdrawals"
        //         "walletHandleTime":"1536232111669",// present in "fetchWithdrawals"
        //         "feeCoinId ":"BHC",                // present in "fetchWithdrawals"
        //         "feeCoinName ":"BHC",              // present in "fetchWithdrawals"
        //         "fee":"0.1",                       // present in "fetchWithdrawals"
        //         "kernelId":"",                     // present in "fetchWithdrawals"
        //         "isInternalTransfer": false        // present in "fetchWithdrawals"
        //     }
        //
        // withdraw
        //
        //     {
        //         "status": 0,
        //         "success": true,
        //         "needBrokerAudit": false, // Do you need a brokerage review?
        //         "id": "423885103582776064",
        //         "refuseReason":"" // failure rejection reason
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transaction, "time");
        Object currencyId = this.safeString2(transaction, "coin", "coinId");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object feeString = this.safeString(transaction, "fee");
        Object feeCoin = this.safeString(transaction, "feeCoinName");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeString, null)))
        {
            final Object finalFeeString = feeString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", ToobitCore.this.parseNumber(finalFeeString) );
                put( "currency", ToobitCore.this.safeCurrencyCode(feeCoin) );
            }};
        }
        Object tagTo = this.safeString2(transaction, "addressTag", "addressExt");
        Object tagFrom = this.safeString(transaction, "fromAddressTag");
        Object addressTo = this.safeString(transaction, "address");
        Object addressFrom = this.safeString(transaction, "fromAddress");
        Object isWithdraw = (Helpers.inOp(transaction, "arriveQuantity"));
        Object type = ((Helpers.isTrue(isWithdraw))) ? "withdrawal" : "deposit";
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", ToobitCore.this.safeString(transaction, "id") );
            put( "txid", ToobitCore.this.safeString(transaction, "txId") );
            put( "timestamp", timestamp );
            put( "datetime", ToobitCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", null );
            put( "addressTo", addressTo );
            put( "addressFrom", addressFrom );
            put( "tag", null );
            put( "tagTo", tagTo );
            put( "tagFrom", tagFrom );
            put( "type", type );
            put( "amount", ToobitCore.this.safeNumber(transaction, "quantity") );
            put( "currency", code );
            put( "status", ToobitCore.this.parseTransactionStatus(ToobitCore.this.safeString(transaction, "status")) );
            put( "updated", null );
            put( "fee", finalFee );
            put( "comment", null );
            put( "internal", null );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "2", "pending" );
            put( "12", "pending" );
            put( "11", "failed" );
            put( "3", "ok" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return null;
        }
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name toobit#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://toobit-docs.github.io/apidocs/spot/v1/en/#deposit-address-user_data
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "coin", Helpers.GetValue(currency, "id") );
            }};
            var networkCodeparamsOmittedVariable = this.handleNetworkCodeAndParams(this.extend(request, parameters));
            var networkCode = ((java.util.List<Object>) networkCodeparamsOmittedVariable).get(0);
            var paramsOmitted = ((java.util.List<Object>) networkCodeparamsOmittedVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(networkCode, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchDepositAddress() : param[\"network\"] is required")) ;
            }
            Helpers.addElementToObject(request, "chainType", this.networkCodeToId(networkCode, code));
            Object response = (this.privateGetApiV1AccountDepositAddress(this.extend(request, paramsOmitted))).join();
            //
            //     {
            //         "canDeposit":false,//Is it possible to recharge
            //         "address":"0x815bF1c3cc0f49b8FC66B21A7e48fCb476051209",
            //         "addressExt":"address tag",
            //         "minQuantity":"100",//minimum amount
            //         "requiredConfirmTimes ":1,//Arrival confirmation number
            //         "canWithdrawConfirmNum ":12,//Withdrawal confirmation number
            //         "coinType":"ERC20_TOKEN"
            //     }
            //
            return this.parseDepositAddress(response, currency);
        });

    }

    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "address");
        this.checkAddress(address);
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", ToobitCore.this.safeString(currency, "code") );
            put( "network", null );
            put( "address", address );
            put( "tag", ToobitCore.this.safeString(depositAddress, "addressExt") );
        }};
    }

    /**
     * @method
     * @name toobit#withdraw
     * @description make a withdrawal
     * @see https://toobit-docs.github.io/apidocs/spot/v1/en/#withdraw-user_data
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag a memo for the transaction
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            this.checkAddress(address);
            Object networkCode = null;
            var networkCodeparametersVariable = this.handleNetworkCodeAndParams(parameters);
            networkCode = ((java.util.List<Object>) networkCodeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) networkCodeparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isEqual(networkCode, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() : param[\"network\"] is required")) ;
            }
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            final Object finalNetworkCode = networkCode;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "coin", Helpers.GetValue(currency, "id") );
                put( "address", address );
                put( "quantity", ToobitCore.this.currencyToPrecision(Helpers.GetValue(currency, "code"), amount) );
                put( "chainType", finalNetworkCode );
                put( "clientOrderId", ToobitCore.this.milliseconds() );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "addressExt", tag);
            }
            Object response = (this.privatePostApiV1AccountWithdraw(this.extend(request, parameters))).join();
            //
            // {
            //     "status": 0,
            //     "success": true,
            //     "needBrokerAudit": false, // Do you need a brokerage review?
            //     "id": "423885103582776064", // Withdrawal successful order id
            //     "refuseReason":"" // failure rejection reason
            // }
            //
            return this.parseTransaction(response, currency);
        });

    }

